export enum Role {
  CLASH = 'Clash Lane',
  JUNGLE = 'Jungler',
  MID = 'Mid Lane',
  FARM = 'Farm Lane',
  ROAM = 'Roam',
  COACH = 'Coach',
}

export interface PlayerStats {
  matchesPlayed: number;
  wins: number;
  currentStreak: number;
  maxStreak: number;
}

export interface Player {
  id: string;
  name: string;
  roles: Role[]; 
  isAllRoles: boolean;
  isActive: boolean;
  isLastMatchMvp?: boolean;
  lastMatchRating?: number;
  stats: PlayerStats;
}

export interface TeamSlot {
  role: Role;
  player: Player;
}

export interface BracketTeam {
  name: string;
  slots: TeamSlot[];
  color: string;
}

export interface TournamentMatch {
  id: string;
  type: 'BO1' | 'BO3';
  label: string;
  teamA: string | null; // Team Name
  teamB: string | null; // Team Name
  winner: string | null;
  scoreA: number;
  scoreB: number;
  isCompleted: boolean;
}

export interface MatchResult {
  roomId: string;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
  bracketTeams?: BracketTeam[]; 
  isCoachMode: boolean;
  isBracketMode: boolean;
  bracketMatchId?: string; // Track which match in a tournament this is
  timestamp: number;
}

export interface MatchHistoryEntry extends MatchResult {
  id: string;
  winningTeam: 'azure' | 'crimson' | string | null; 
  mvpId?: string;
  ratings?: Record<string, number>;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry, TournamentMatch, BracketTeam } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { MatchSummary } from './components/MatchSummary';
import { generateMatch, generateBracket } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';
import { LocalClock } from './components/LocalClock';

const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'tournament' | 'match' | 'battle';

const STORAGE_KEY_PLAYERS = 'hok_roster_data_v2';
const STORAGE_KEY_HISTORY = 'hok_match_history_v2';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [players, setPlayers] = useState<Player[]>(() => {
    try {
      if (window.location.hash && window.location.hash.length > 1) {
        const hashData = window.location.hash.substring(1);
        const decoded = JSON.parse(atob(hashData));
        if (Array.isArray(decoded)) return decoded;
      }
      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    }
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [tournamentMatches, setTournamentMatches] = useState<TournamentMatch[]>([]);
  const [tournamentTeams, setTournamentTeams] = useState<BracketTeam[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [bracketTeamCount, setBracketTeamCount] = useState(4);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));
    try {
      const compactData = players.map(p => ({ id: p.id, name: p.name, roles: p.roles, isAllRoles: p.isAllRoles, isActive: p.isActive, stats: p.stats }));
      const hash = btoa(JSON.stringify(compactData));
      if (hash.length < 2000) window.history.replaceState(null, '', `#${hash}`);
    } catch (e) {}
  }, [players]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(), name: item.name, roles: item.roles, isAllRoles: item.isAllRoles, isActive: true, isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim() || roomId.length < 4) { setErrorMsg("Please enter a valid 4-digit Room ID."); return; }

    if (isBracketMode) {
      if (activePlayers.length < bracketTeamCount * 5) { setErrorMsg(`Need ${bracketTeamCount * 5} ACTIVE players for ${bracketTeamCount} teams.`); return; }
      const result = generateBracket(activePlayers, roomId, bracketTeamCount);
      if (result && result.bracketTeams) {
        setTournamentTeams(result.bracketTeams);
        const teams = result.bracketTeams;
        let initialMatches: TournamentMatch[] = [];
        if (bracketTeamCount === 4) {
          initialMatches = [
            { id: 'm1', type: 'BO1', label: 'Semi-Final 1', teamA: teams[0].name, teamB: teams[1].name, winner: null, scoreA: 0, scoreB: 0, isCompleted: false },
            { id: 'm2', type: 'BO1', label: 'Semi-Final 2', teamA: teams[2].name, teamB: teams[3].name, winner: null, scoreA: 0, scoreB: 0, isCompleted: false },
            { id: 'final', type: 'BO3', label: 'Grand Final', teamA: null, teamB: null, winner: null, scoreA: 0, scoreB: 0, isCompleted: false },
          ];
        } else if (bracketTeamCount === 2) {
          initialMatches = [
            { id: 'final', type: 'BO3', label: 'Grand Final', teamA: teams[0].name, teamB: teams[1].name, winner: null, scoreA: 0, scoreB: 0, isCompleted: false }
          ];
        }
        setTournamentMatches(initialMatches);
        setViewMode('tournament');
        setErrorMsg(null);
      }
    } else {
      const required = isCoachMode ? 12 : 10;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players. Current: ${activePlayers.length}`); return; }
      const result = generateMatch(activePlayers, roomId, isCoachMode);
      if (result) { setCurrentMatch(result); setErrorMsg(null); setViewMode('match'); }
      else { setErrorMsg("Failed to find valid composition."); }
    }
  };

  const handlePlayTournamentMatch = (matchId: string) => {
    const tMatch = tournamentMatches.find(m => m.id === matchId);
    if (!tMatch || !tMatch.teamA || !tMatch.teamB) return;

    const teamA = tournamentTeams.find(t => t.name === tMatch.teamA)!;
    const teamB = tournamentTeams.find(t => t.name === tMatch.teamB)!;

    const matchResult: MatchResult = {
      roomId,
      azureTeam: teamA.slots,
      crimsonTeam: teamB.slots,
      isCoachMode: false,
      isBracketMode: true,
      bracketMatchId: matchId,
      timestamp: Date.now()
    };

    setCurrentMatch(matchResult);
    setViewMode('match');
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | string | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // Update Tournament Bracket if applicable
    if (isBracketMode && currentMatch.bracketMatchId) {
      setTournamentMatches(prev => {
        const updated = prev.map(m => {
          if (m.id === currentMatch.bracketMatchId) {
            const winnerName = winner === 'azure' ? m.teamA : (winner === 'crimson' ? m.teamB : null);
            return { 
                ...m, 
                winner: winnerName, 
                scoreA: winner === 'azure' ? (m.type === 'BO3' ? 2 : 1) : 0,
                scoreB: winner === 'crimson' ? (m.type === 'BO3' ? 2 : 1) : 0,
                isCompleted: true 
            };
          }
          return m;
        });

        // Advance logic for 4-team bracket
        if (currentMatch.bracketMatchId === 'm1' || currentMatch.bracketMatchId === 'm2') {
          const m1 = updated.find(m => m.id === 'm1');
          const m2 = updated.find(m => m.id === 'm2');
          const finalMatch = updated.find(m => m.id === 'final');
          if (finalMatch) {
              if (m1?.winner) finalMatch.teamA = m1.winner;
              if (m2?.winner) finalMatch.teamB = m2.winner;
          }
        }
        return updated;
      });
    }

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      const isParticipant = currentMatch.azureTeam.some(s => s.player.id === p.id) || currentMatch.crimsonTeam.some(s => s.player.id === p.id);

      if (!isParticipant) return { ...p, isLastMatchMvp: false };

      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
      let isWinner = false;
      const isAzure = currentMatch.azureTeam.some(s => s.player.id === p.id);
      isWinner = !!(winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson')));

      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }

      return { ...p, stats: newStats, isLastMatchMvp, lastMatchRating: ratings?.[p.id] || 0 };
    });

    setPlayers(updatedPlayers);
    setCurrentMatch(null);
    if (isBracketMode) {
      setViewMode('tournament');
    } else {
      setViewMode('lobby');
      setRoomId('');
    }
  };

  const handleClearAll = () => { if (window.confirm("Clear all players?")) setPlayers([]); };

  const handleRerollSlot = (team: 'azure' | 'crimson' | string, role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    let updatedMatch = { ...currentMatch };
    updatedMatch.azureTeam = currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot);
    updatedMatch.crimsonTeam = currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot);
    setCurrentMatch(updatedMatch); 
    setViewMode('match');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const count = isBracketMode ? bracketTeamCount * 5 : 20;
     const batchData = shuffledHeroes.slice(0, count).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     handleBatchProcess(batchData);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <LocalClock />
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>
      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <main className="relative z-10 pt-16 px-4 flex-grow max-w-7xl mx-auto w-full">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className={`lg:col-span-4 space-y-6 ${isSidebarOpen ? '' : 'hidden'}`}>
              <div className="relative group">
                <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative overflow-hidden">
                  <div className="flex items-center justify-between mb-4 border-b border-[#dcb06b]/20 pb-2">
                    <h3 className="text-sm text-[#dcb06b] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room</h3>
                    <span className={`text-[10px] font-orbitron font-bold transition-colors duration-300 ${roomId.length === 4 ? 'text-green-500' : 'text-red-500'}`}>LOBBY: {roomId.length === 4 ? 'READY' : 'NOT READY'}</span>
                  </div>
                  <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className={`bg-black/40 border border-[#1e3a5f] p-4 text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all clip-corner-sm ${roomId ? 'text-white border-[#dcb06b]' : 'text-[#4a5f78] opacity-60'}`}/>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => { setIsCoachMode(!isCoachMode); setIsBracketMode(false); }} className={`relative group p-[2px] clip-corner-sm transition-all ${isCoachMode ? 'scale-105' : 'opacity-60'}`}>
                   {isCoachMode && <div className="absolute inset-[-100%] animate-[spin_3s_linear_infinite] bg-[conic-gradient(from_0deg,transparent_0deg,#dcb06b_60deg,transparent_180deg,#dcb06b_240deg,transparent_360deg)]"></div>}
                   <div className={`relative z-10 py-3 px-4 flex items-center justify-center clip-corner-sm border ${isCoachMode ? 'bg-black text-[#dcb06b] border-transparent' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>
                      <span className="font-cinzel font-black text-[10px] tracking-widest uppercase">COACH MODE</span>
                   </div>
                </button>
                <button onClick={() => { setIsBracketMode(!isBracketMode); setIsCoachMode(false); }} className={`relative group p-[2px] clip-corner-sm transition-all ${isBracketMode ? 'scale-105' : 'opacity-60'}`}>
                   {isBracketMode && <div className="absolute inset-[-100%] animate-[spin_3s_linear_infinite] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_60deg,transparent_180deg,#ffffff_240deg,transparent_360deg)]"></div>}
                   <div className={`relative z-10 py-3 px-4 flex items-center justify-center clip-corner-sm border ${isBracketMode ? 'bg-black text-white border-transparent' : 'bg-[#0a1a2f] border-[#1e3a5f] text-[#4a5f78]'}`}>
                      <span className="font-cinzel font-black text-[10px] tracking-widest uppercase">BRACKET MODE</span>
                   </div>
                </button>
              </div>

              {isBracketMode && (
                <div className="bg-[#0a1a2f]/90 p-4 border border-white/20 clip-corner-sm animate-slide-in">
                  <label className="text-[10px] font-bold text-white/70 uppercase tracking-widest mb-3 block">Number of Teams</label>
                  <div className="grid grid-cols-4 gap-2">
                    {[2, 4].map(n => (
                      <button key={n} onClick={() => setBracketTeamCount(n)} className={`py-2 text-xs font-bold font-orbitron clip-corner-sm border transition-all ${bracketTeamCount === n ? 'bg-white text-black border-white' : 'bg-black/50 text-white/50 border-white/10 hover:border-white/50'}`}>{n}</button>
                    ))}
                  </div>
                </div>
              )}

              <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />
              <div className="relative group">
                <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                <div className="bg-[#0a1a2f]/90 p-6 clip-corner-md relative">
                   <div className="flex justify-between items-end mb-6">
                      <div>
                         <div className="text-[#8a9db8] text-[10px] uppercase font-bold mb-1">Active Players</div>
                         <div className="flex items-baseline gap-2">
                            <div className="text-5xl font-orbitron font-bold text-white">{activePlayers.length}</div>
                            <div className="text-xl font-orbitron font-bold text-[#4a5f78]">/ {players.length}</div>
                         </div>
                      </div>
                      <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] transition-colors">Quick Fill</button>
                   </div>
                   {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">{errorMsg}</div>}
                   <Button onClick={handleGenerate} className="w-full" disabled={activePlayers.length < (isBracketMode ? bracketTeamCount * 5 : (isCoachMode ? 12 : 10)) || roomId.length !== 4}>START MATCHMAKING</Button>
                </div>
              </div>
            </div>
            <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
               <div className="flex items-center justify-between mb-6">
                  <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] bg-[#0a1a2f]/50 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg></button>
                  <h2 className="text-2xl font-cinzel font-black text-[#dcb06b]">SQUAD ROSTER</h2>
                  <button onClick={handleClearAll} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase transition-colors">Clear All</button>
               </div>
               <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px]">
                  <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} />
               </div>
               <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                  <h2 className="text-2xl font-cinzel font-black text-[#dcb06b] mb-6">BATTLE HISTORY</h2>
                  <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
               </div>
            </div>
          </div>
        </main>
      )}

      {viewMode === 'tournament' && (
        <MatchSummary 
          match={{ roomId, azureTeam: [], crimsonTeam: [], isCoachMode: false, isBracketMode: true, bracketTeams: tournamentTeams, timestamp: Date.now() }} 
          tournamentMatches={tournamentMatches}
          onPlayMatch={handlePlayTournamentMatch}
          onReset={(winner) => { setViewMode('lobby'); setRoomId(''); }} 
        />
      )}

      {currentMatch && (viewMode === 'match' || viewMode === 'battle') && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'} 
          onReset={() => { 
            if (isBracketMode) setViewMode('tournament');
            else { setCurrentMatch(null); setViewMode('lobby'); }
          }} 
          onCompleteMatch={handleMatchFinish} 
          onReroll={handleRerollSlot} 
          onStartBattle={() => setViewMode('battle')} 
        />
      )}
    </div>
  );
}

import React from 'react';
import { MatchResult, TeamSlot, Role, TournamentMatch } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface MatchSummaryProps {
  match: MatchResult;
  tournamentMatches?: TournamentMatch[];
  onPlayMatch?: (matchId: string) => void;
  onReset: (winner: string | 'azure' | 'crimson' | null) => void;
}

export const MatchSummary: React.FC<MatchSummaryProps> = ({ match, tournamentMatches, onPlayMatch, onReset }) => {
  const getTeamByName = (name: string) => match.bracketTeams?.find(t => t.name === name);
  const getPlayer = (slots: TeamSlot[], role: Role) => slots.find(s => s.role === role)?.player;

  const renderMatchCard = (m: TournamentMatch) => {
    const teamA = m.teamA ? getTeamByName(m.teamA) : null;
    const teamB = m.teamB ? getTeamByName(m.teamB) : null;
    const isCompleted = m.isCompleted;

    return (
      <div key={m.id} className="relative bg-[#0a1a2f]/80 border border-[#1e3a5f] clip-corner-sm p-4 w-full max-w-sm transition-all hover:border-[#dcb06b]/40">
        <div className="flex justify-between items-center mb-3">
          <span className="text-[10px] font-orbitron font-black text-[#dcb06b] tracking-widest">{m.label}</span>
          <span className="text-[10px] font-bold bg-white/5 px-2 py-0.5 text-white/40 rounded">{m.type}</span>
        </div>

        <div className="space-y-2">
          {/* Team A Row */}
          <div className={`flex items-center justify-between p-2 rounded ${m.winner === m.teamA && isCompleted ? 'bg-[#dcb06b]/20 border border-[#dcb06b]/30' : 'bg-black/20'}`}>
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-6 skew-x-[-12deg]" style={{ backgroundColor: teamA?.color || '#334155' }}></div>
              <span className={`font-orbitron font-bold text-sm ${!teamA ? 'text-gray-600 italic' : 'text-white'}`}>
                {teamA ? teamA.name : 'TBD'}
              </span>
            </div>
            {isCompleted && m.winner === m.teamA && <span className="font-orbitron font-black text-[#dcb06b]">WIN</span>}
          </div>

          <div className="text-center text-[10px] font-black text-gray-700">VS</div>

          {/* Team B Row */}
          <div className={`flex items-center justify-between p-2 rounded ${m.winner === m.teamB && isCompleted ? 'bg-[#dcb06b]/20 border border-[#dcb06b]/30' : 'bg-black/20'}`}>
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-6 skew-x-[-12deg]" style={{ backgroundColor: teamB?.color || '#334155' }}></div>
              <span className={`font-orbitron font-bold text-sm ${!teamB ? 'text-gray-600 italic' : 'text-white'}`}>
                {teamB ? teamB.name : 'TBD'}
              </span>
            </div>
            {isCompleted && m.winner === m.teamB && <span className="font-orbitron font-black text-[#dcb06b]">WIN</span>}
          </div>
        </div>

        {!isCompleted && teamA && teamB && (
            <div className="mt-4">
                <Button onClick={() => onPlayMatch?.(m.id)} size="sm" className="w-full h-8">START MATCH</Button>
            </div>
        )}

        {isCompleted && m.id === 'final' && (
            <div className="mt-4 animate-pulse">
                <Button onClick={() => onReset(m.winner)} size="sm" className="w-full">CROWN CHAMPION</Button>
            </div>
        )}
      </div>
    );
  };

  if (match.isBracketMode && tournamentMatches && tournamentMatches.length > 0) {
    return (
      <div className="fixed inset-0 z-[60] bg-[#05090f]/95 backdrop-blur-md flex flex-col items-center p-8 overflow-y-auto">
        <div className="w-full max-w-7xl animate-slide-in py-10 flex flex-col items-center">
          <div className="text-center mb-16">
            <h1 className="text-5xl font-cinzel font-black text-white tracking-[0.2em] mb-4">TOURNAMENT BRACKET</h1>
            <div className="h-1 w-48 bg-[#dcb06b] mx-auto opacity-50"></div>
            <p className="text-[#4a5f78] font-orbitron text-[10px] tracking-[0.5em] mt-4 uppercase">Semi-Finals BO1 • Grand Final BO3</p>
          </div>

          <div className="flex flex-col lg:flex-row items-center justify-center gap-12 lg:gap-24 w-full">
            {/* Semi Finals Column */}
            {tournamentMatches.length > 1 && (
              <div className="flex flex-col gap-12 w-full max-w-sm">
                {tournamentMatches.filter(m => m.id.startsWith('m')).map(renderMatchCard)}
              </div>
            )}

            {/* Finals Column */}
            <div className="w-full max-w-sm flex flex-col items-center">
              <div className="mb-4 text-[#dcb06b] font-cinzel font-black text-xl tracking-[0.3em] animate-pulse">THE ARENA</div>
              {tournamentMatches.filter(m => m.id === 'final').map(renderMatchCard)}
            </div>
          </div>

          <div className="mt-20 flex flex-col items-center gap-6">
             <Button onClick={() => onReset(null)} variant="outline" className="px-12 border-white/10 text-white/40">ABORT TOURNAMENT</Button>
          </div>
        </div>
      </div>
    );
  }

  // Standard Dual Mode Summary (Used during the end of a match before evaluation)
  return (
    <div className="fixed inset-0 z-[60] bg-[#05090f]/95 backdrop-blur-md flex flex-col items-center p-8 overflow-y-auto">
       <div className="w-full max-w-7xl animate-slide-in py-10">
          <div className="text-center mb-12">
             <h1 className="text-5xl font-cinzel font-black text-white tracking-[0.2em] mb-4">BATTLE SUMMARY</h1>
             <div className="h-1 w-48 bg-[#dcb06b] mx-auto opacity-50"></div>
          </div>

          <div className={`grid gap-8 mb-20 grid-cols-1 lg:grid-cols-2`}>
             {[{ name: 'azure', slots: match.azureTeam, color: '#00d2ff' }, { name: 'crimson', slots: match.crimsonTeam, color: '#ef4444' }].map((team: any) => (
                <div key={team.name} className="bg-[#0a1a2f]/50 border-t-4 p-6 clip-corner-sm shadow-xl" style={{ borderColor: team.color }}>
                   <h2 className="text-xl font-cinzel font-black text-white mb-6 flex justify-between items-center">
                      {team.name.toUpperCase()}
                   </h2>
                   <div className="space-y-3">
                      {ROLES_ORDER.map(role => {
                         const p = getPlayer(team.slots, role);
                         return (
                            <div key={role} className="flex items-center gap-3 bg-black/30 p-2 rounded border border-white/5">
                               <div className="shrink-0 scale-75 opacity-70" style={{ color: team.color }}>{RoleIcons[role]}</div>
                               <div className="text-white font-orbitron font-bold truncate">{p?.name}</div>
                            </div>
                         );
                      })}
                   </div>
                   <button onClick={() => onReset(team.name)} className="w-full mt-6 py-3 font-cinzel font-black text-xs border-2 hover:bg-white hover:text-black transition-all clip-corner-sm" style={{ borderColor: team.color, color: team.color }}>DECLARE VICTORY</button>
                </div>
             ))}
          </div>

          <div className="flex justify-center">
             <Button onClick={() => onReset(null)} variant="secondary" className="px-20 border-white/20 text-white/50">MATCH DRAW / ABORT</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | string | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson' | string, role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | string | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());
  const [wheelState, setWheelState] = useState<any>(null);

  useEffect(() => {
     setViewState(initialMode === 'battle' ? 'final' : 'drafting');
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const getCardId = (team: string, role: Role) => `${team}-${role}`;

  const handleNext = () => {
    let nextReveal: { teamName: string; role: Role } | null = null;
    const teamNames = ['azure', 'crimson'];

    for (const role of displayRoles) {
      for (const teamName of teamNames) {
        const cid = getCardId(teamName, role);
        if (!revealedCards.has(cid)) {
          nextReveal = { teamName, role };
          break;
        }
      }
      if (nextReveal) break;
    }

    if (nextReveal) {
      startWheel(nextReveal.teamName, nextReveal.role);
    }
  };

  const startWheel = (teamName: string, role: Role) => {
    const teamColor = teamName === 'azure' ? '#00d2ff' : '#ef4444';
    const teamSlots = teamName === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = teamSlots.find(s => s.role === role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    const teams = [{ id: 'azure', slots: match.azureTeam }, { id: 'crimson', slots: match.crimsonTeam }];

    teams.forEach(t => {
       t.slots.forEach(slot => {
          if (revealedCards.has(getCardId(t.id, slot.role))) revealedPlayerIds.add(slot.player.id);
       });
    });

    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (role === Role.COACH ? p.roles.includes(Role.COACH) : (p.isAllRoles || p.roles.includes(role))));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    if (candidateNames.length <= 1) {
        const cid = getCardId(teamName, role);
        setAutoFillFlash(cid);
        setRevealedCards(prev => {
          const newSet = new Set(prev);
          newSet.add(cid);
          return newSet;
        });
        setTimeout(() => setAutoFillFlash(null), 800);
        return;
    }

    setWheelState({ 
        isOpen: true, 
        type: 'draft', 
        team: teamName, 
        color: teamColor,
        roleName: role,
        winnerName: winner.name, 
        candidates: candidateNames, 
        duration: 5000 + Math.random() * 3000 
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    const cid = getCardId(wheelState.team, wheelState.roleName);
    setRevealedCards(prev => {
      const newSet = new Set(prev);
      newSet.add(cid);
      return newSet;
    });
    setWheelState(null);
  };

  const renderCard = (role: Role, teamName: string, color: string) => {
    const cardId = getCardId(teamName, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const teamSlots = teamName === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = teamSlots?.find(s => s.role === role)?.player;

    if (!isRevealed) {
      return (
        <div className="h-16 w-full border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-30 clip-corner-sm group hover:opacity-50 transition-all">
           <div className="text-[#1e3a5f] transform scale-75 group-hover:text-white/20">{RoleIcons[role]}</div>
        </div>
      );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 border-l-4 clip-corner-sm flex items-center px-4 bg-[#0a1a2f] shadow-lg transition-all`} style={{ borderColor: color }}>
           <div className="flex-1 min-w-0">
             <div className="text-[8px] uppercase font-black opacity-50 flex items-center gap-1" style={{ color }}>
                {RoleIcons[role]}
             </div>
             <div className="text-white font-orbitron font-bold text-lg truncate drop-shadow-sm">{player?.name}</div>
           </div>
        </div>
      </div>
    );
  };

  const totalRequired = match.isCoachMode ? 12 : 10;
  const isFinished = revealedCards.size === totalRequired;

  return (
    <div className="min-h-screen bg-[#05090f] flex flex-col items-center justify-center p-4 relative overflow-hidden z-[50]">
      {wheelState?.isOpen && <SpinWheel {...wheelState} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} roomId={match.roomId} />}

      <div className="absolute top-6 left-6 right-6 flex justify-between items-center z-[60]">
         <Button variant="outline" size="sm" onClick={onReset} className="text-red-500 border-red-900/40">ABORT</Button>
         <div className="bg-black/80 border border-[#dcb06b]/50 px-6 py-2 clip-corner-sm font-orbitron font-black text-white text-xl tracking-[0.3em] shadow-[0_0_15px_rgba(220,176,107,0.2)]">{match.roomId}</div>
         <Button variant="outline" size="sm" onClick={() => { 
           const all = new Set<string>();
           ['azure', 'crimson'].forEach(t => displayRoles.forEach(r => all.add(getCardId(t, r))));
           setRevealedCards(all);
         }} className="text-[#dcb06b] border-[#dcb06b]/40">SKIP</Button>
      </div>

      <div className="w-full max-w-4xl flex-1 flex flex-col justify-center gap-8 py-20 px-6 overflow-y-auto">
        <div className="grid grid-cols-2 gap-x-12 gap-y-12 items-start">
           {[{ name: 'azure', color: '#00d2ff' }, { name: 'crimson', color: '#ef4444' }].map((team) => (
              <div key={team.name} className="space-y-4">
                 <div className="flex flex-col mb-4">
                    <h2 className="font-cinzel font-black text-2xl tracking-widest text-white drop-shadow-md">{team.name.toUpperCase()}</h2>
                    <div className="h-1 w-full mt-1 opacity-50" style={{ background: `linear-gradient(to right, ${team.color}, transparent)` }}></div>
                 </div>
                 {displayRoles.map(role => (
                    <div key={role}>{renderCard(role, team.name, team.color)}</div>
                 ))}
              </div>
           ))}
        </div>
      </div>

      {!isFinished && (
        <div className="fixed bottom-8 z-[60]">
            <Button onClick={handleNext} size="lg" className="px-16 h-16 shadow-[0_0_30px_rgba(220,176,107,0.4)]">NEXT REVEAL</Button>
        </div>
      )}

      {isFinished && viewState === 'drafting' && (
        <div className="fixed bottom-8 z-[60]">
            <Button onClick={onStartBattle} size="lg" className="px-20 h-16 bg-white text-black border-white animate-pulse">START BATTLE</Button>
        </div>
      )}

      {viewState === 'final' && (
        <MatchSummary 
          match={match} 
          onReset={(winner) => { 
            if (winner) {
                setWinningTeam(winner); 
                setViewState('celebration');
            } else {
                onCompleteMatch(null);
            }
          }} 
        />
      )}

      {viewState === 'celebration' && winningTeam && (
        <VictoryCelebration 
            winner={winningTeam as any} 
            teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} 
            onDismiss={() => setViewState('evaluation')} 
        />
      )}

      {viewState === 'evaluation' && winningTeam && (
        <EvaluationScreen 
            match={match} 
            winner={winningTeam as any} 
            onComplete={(mvp, ratings) => onCompleteMatch(winningTeam, mvp, ratings)} 
        />
      )}
    </div>
  );
};
